  isValidEmail(email) {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }
  deleteSelectedUsers() {
    if (!this.selectedUsers || this.selectedUsers.length === 0) {
      this.messageService.add({ severity: "warn", summary: "Warning", detail: "Please select users to delete" });
      return;
    }
    import_sweetalert2.default.fire({
      title: "Confirm Delete",
      text: `Are you sure you want to delete ${this.selectedUsers.length} user(s)?`,
      icon: "warning",
      showCancelButton: true,
      confirmButtonText: "Yes, Delete All",
      cancelButtonText: "Cancel"
    }).then((result) => {
      if (result.isConfirmed) {
        let deletedCount = 0;
        let failedCount = 0;
        this.selectedUsers.forEach((user) => {
          const userId = user.userId || user.user_id;
          this.userService.deleteUser(userId).subscribe({
            next: () => {
              deletedCount++;
              if (deletedCount + failedCount === this.selectedUsers.length) {
                this.selectedUsers = [];
                this.loadUsers();
                import_sweetalert2.default.fire({
                  title: "Deleted!",
                  text: `${deletedCount} user(s) deleted successfully.`,
                  icon: "success"
                });
              }
            },
            error: (error) => {
              failedCount++;
              console.error(`Failed to delete user ${userId}:`, error);
              if (deletedCount + failedCount === this.selectedUsers.length) {
                this.selectedUsers = [];
                this.loadUsers();
                import_sweetalert2.default.fire({
                  title: "Partial Delete",
                  text: `${deletedCount} user(s) deleted, ${failedCount} failed.`,
                  icon: "warning"
                });
              }
            }
          });
        });
      }
    });
  }
  exportToExcel() {
    if (this.filteredUsers.length === 0) {
      this.messageService.add({ severity: "warn", summary: "Warning", detail: "No data to export" });
      return;
    }
    const data = this.filteredUsers.map((user) => ({
      "User ID": user.userId || "",
      "First Name": user.firstName || "",
      "Middle Name": user.middleName || "",
      "Last Name": user.lastName || "",
      Email: user.email || "",
      Contact: user.contactNumber || "",
      Campus: user.campus?.campusName || "",
      Department: user.department?.departmentName || "",
      Role: user.role || "",
      Status: user.isActive ? "Active" : "Inactive"
    }));
    const headers = Object.keys(data[0] || {});
    const csvContent = [
      headers.join(","),
      ...data.map((row) => headers.map((header) => {
        const value = row[header] || "";
        const escaped = String(value).replace(/"/g, '""');
        return escaped.includes(",") || escaped.includes('"') ? `"${escaped}"` : escaped;
      }).join(","))
    ].join("\n");
    const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    const campusName = this.selectedCampus ? this.campuses.find((c2) => c2.campusId === this.selectedCampus)?.campusName || "filtered" : "all";
    const filename = `users_${campusName}_${(/* @__PURE__ */ new Date()).toISOString().split("T")[0]}.csv`;
    link.setAttribute("href", url);
    link.setAttribute("download", filename);
    link.style.visibility = "hidden";
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    this.messageService.add({
      severity: "success",
      summary: "Exported",
      detail: `${this.filteredUsers.length} users exported to ${filename}`,
      life: 3e3
    });
  }
